# solution.py
"""Team Collaboration Manager.

A thread-safe, in-memory collaboration backend supporting:

* Users (registration, roles, lookup, update, delete).
* Projects (creation, scheduling, cascade deletion).
* Tasks (assignment, status transitions, deadlines).
* Messaging (project/task threads, replies, attachments).
* Performance metrics (completion rate, completion time, ratings, dashboards).
* Reporting (project progress, team and individual performance) with CSV and
  PDF export.

The module is implemented with the standard library only so that the bundled
unittest suite can exercise it without any third-party dependencies.
"""

from __future__ import annotations

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Callable, Dict, List, Optional, Sequence, Tuple


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class UserRole(Enum):
    """Roles a user can hold inside the collaboration space."""

    MEMBER = "member"
    ADMIN = "admin"


class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class ReportFormat(Enum):
    """Supported export formats for generated reports."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for every error raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when supplied data fails a validation rule."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an operation."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint would be violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with existing state."""


# ---------------------------------------------------------------------------
# Entities
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    created_at: datetime
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus
    created_at: datetime
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    description: str = ""
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    created_at: datetime
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    created_at: datetime
    feedback: str = ""
    task_id: Optional[int] = None


# ---------------------------------------------------------------------------
# Internal storage primitive
# ---------------------------------------------------------------------------
class _Store:
    """A lock-sharing container for a family of entities.

    Every store shares the *same* lock instance with its owning manager so that
    cross-store operations remain atomic.  Tests rely on this shared identity.
    """

    def __init__(self, lock: "threading.RLock") -> None:
        self._lock = lock
        self.items: Dict[int, object] = {}


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, and reporting."""

    def __init__(self, now: Optional[Callable[[], datetime]] = None) -> None:
        self._lock = threading.RLock()
        self._now_fn: Callable[[], datetime] = now if now is not None else datetime.now
        self._id_counter = 0

        # Primary stores (all share the single manager lock).
        self.users = _Store(self._lock)
        self.projects = _Store(self._lock)
        self.tasks = _Store(self._lock)
        self.messages = _Store(self._lock)
        self.performance = _Store(self._lock)  # holds Rating entities
        self.reports = _Store(self._lock)

        # Secondary indexes.
        self._tasks_by_assignee: Dict[int, set] = {}
        self._ratings_by_ratee: Dict[int, List[int]] = {}

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _now(self) -> datetime:
        return self._now_fn()

    def _next_id(self) -> int:
        self._id_counter += 1
        return self._id_counter

    def _user_or_raise(self, user_id: int) -> User:
        user = self.users.items.get(user_id)
        if user is None:
            raise NotFoundError("user {0} not found".format(user_id))
        return user  # type: ignore[return-value]

    def _project_or_raise(self, project_id: int) -> Project:
        project = self.projects.items.get(project_id)
        if project is None:
            raise NotFoundError("project {0} not found".format(project_id))
        return project  # type: ignore[return-value]

    def _task_or_raise(self, task_id: int) -> Task:
        task = self.tasks.items.get(task_id)
        if task is None:
            raise NotFoundError("task {0} not found".format(task_id))
        return task  # type: ignore[return-value]

    def _message_or_raise(self, message_id: int) -> Message:
        message = self.messages.items.get(message_id)
        if message is None:
            raise NotFoundError("message {0} not found".format(message_id))
        return message  # type: ignore[return-value]

    @staticmethod
    def _is_blank(value: object) -> bool:
        return not isinstance(value, str) or not value.strip()

    @staticmethod
    def _valid_email(email: object) -> bool:
        if not isinstance(email, str):
            return False
        candidate = email.strip()
        if not candidate or candidate.count("@") != 1:
            return False
        local, _, domain = candidate.partition("@")
        return bool(local) and bool(domain)

    def _assignee_task_ids(self, user_id: int) -> List[int]:
        return list(self._tasks_by_assignee.get(user_id, set()))

    def _index_assign(self, task_id: int, assignee_id: Optional[int]) -> None:
        if assignee_id is not None:
            self._tasks_by_assignee.setdefault(assignee_id, set()).add(task_id)

    def _index_unassign(self, task_id: int, assignee_id: Optional[int]) -> None:
        if assignee_id is None:
            return
        bucket = self._tasks_by_assignee.get(assignee_id)
        if bucket is not None:
            bucket.discard(task_id)
            if not bucket:
                self._tasks_by_assignee.pop(assignee_id, None)

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(
        self, username: str, email: str, role: UserRole = UserRole.MEMBER
    ) -> User:
        with self._lock:
            if self._is_blank(username):
                raise ValidationError("username is required")
            if not self._valid_email(email):
                raise ValidationError("a valid email is required")
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            clean_username = username.strip()
            clean_email = email.strip()
            for existing in self.users.items.values():
                if existing.username == clean_username:
                    raise DuplicateError("username already exists")
                if existing.email == clean_email:
                    raise DuplicateError("email already exists")

            user_id = self._next_id()
            user = User(
                id=user_id,
                username=clean_username,
                email=clean_email,
                role=role,
                created_at=self._now(),
            )
            self.users.items[user_id] = user
            return copy.deepcopy(user)

    def get_user(self, user_id: int) -> User:
        with self._lock:
            return copy.deepcopy(self._user_or_raise(user_id))

    def list_users(self) -> List[User]:
        with self._lock:
            ordered = sorted(self.users.items.values(), key=lambda u: u.id)
            return [copy.deepcopy(u) for u in ordered]

    def update_user(
        self,
        user_id: int,
        username: Optional[str] = None,
        email: Optional[str] = None,
        role: Optional[UserRole] = None,
    ) -> User:
        with self._lock:
            user = self._user_or_raise(user_id)

            if username is not None:
                if self._is_blank(username):
                    raise ValidationError("username is required")
                new_username = username.strip()
                for existing in self.users.items.values():
                    if existing.id != user_id and existing.username == new_username:
                        raise DuplicateError("username already exists")
            else:
                new_username = user.username

            if email is not None:
                if not self._valid_email(email):
                    raise ValidationError("a valid email is required")
                new_email = email.strip()
                for existing in self.users.items.values():
                    if existing.id != user_id and existing.email == new_email:
                        raise DuplicateError("email already exists")
            else:
                new_email = user.email

            if role is not None:
                if not isinstance(role, UserRole):
                    raise ValidationError("role must be a UserRole")
                user.role = role

            user.username = new_username
            user.email = new_email
            return copy.deepcopy(user)

    def delete_user(self, user_id: int) -> None:
        with self._lock:
            self._user_or_raise(user_id)

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project and cannot be deleted")

            for task_id in self._assignee_task_ids(user_id):
                task = self.tasks.items.get(task_id)
                if task is not None and task.status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks and cannot be deleted")

            # Detach the user from any remaining (completed) tasks.
            for task_id in self._assignee_task_ids(user_id):
                task = self.tasks.items.get(task_id)
                if task is not None:
                    task.assignee_id = None
            self._tasks_by_assignee.pop(user_id, None)
            self._ratings_by_ratee.pop(user_id, None)
            self.users.items.pop(user_id, None)

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(
        self,
        name: str,
        start_date: datetime,
        end_date: datetime,
        owner_id: int,
        description: str = "",
    ) -> Project:
        with self._lock:
            self._user_or_raise(owner_id)
            if self._is_blank(name):
                raise ValidationError("project name is required")
            if start_date is None or end_date is None:
                raise ValidationError("start and end dates are required")
            if end_date < start_date:
                raise ValidationError("end date cannot precede start date")

            project_id = self._next_id()
            project = Project(
                id=project_id,
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                created_at=self._now(),
                description=description or "",
            )
            self.projects.items[project_id] = project
            return copy.deepcopy(project)

    def get_project(self, project_id: int) -> Project:
        with self._lock:
            return copy.deepcopy(self._project_or_raise(project_id))

    def list_projects(self) -> List[Project]:
        with self._lock:
            ordered = sorted(self.projects.items.values(), key=lambda p: p.id)
            return [copy.deepcopy(p) for p in ordered]

    def update_project(
        self,
        project_id: int,
        name: Optional[str] = None,
        start_date: Optional[datetime] = None,
        end_date: Optional[datetime] = None,
        description: Optional[str] = None,
    ) -> Project:
        with self._lock:
            project = self._project_or_raise(project_id)

            new_name = project.name
            if name is not None:
                if self._is_blank(name):
                    raise ValidationError("project name is required")
                new_name = name.strip()

            new_start = start_date if start_date is not None else project.start_date
            new_end = end_date if end_date is not None else project.end_date
            if new_end < new_start:
                raise ValidationError("end date cannot precede start date")

            project.name = new_name
            project.start_date = new_start
            project.end_date = new_end
            if description is not None:
                project.description = description
            return copy.deepcopy(project)

    def delete_project(self, project_id: int) -> None:
        with self._lock:
            self._project_or_raise(project_id)

            task_ids = [
                tid
                for tid, task in self.tasks.items.items()
                if task.project_id == project_id
            ]
            for task_id in task_ids:
                task = self.tasks.items.pop(task_id)
                self._index_unassign(task_id, task.assignee_id)

            doomed_tasks = set(task_ids)
            message_ids = [
                mid
                for mid, message in self.messages.items.items()
                if message.project_id == project_id or message.task_id in doomed_tasks
            ]
            for message_id in message_ids:
                self.messages.items.pop(message_id, None)

            self.projects.items.pop(project_id, None)

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(
        self,
        project_id: int,
        title: str,
        assignee_id: Optional[int] = None,
        deadline: Optional[datetime] = None,
        description: str = "",
    ) -> Task:
        with self._lock:
            project = self._project_or_raise(project_id)
            if assignee_id is not None:
                self._user_or_raise(assignee_id)
            if self._is_blank(title):
                raise ValidationError("task title is required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline cannot precede project start")

            task_id = self._next_id()
            task = Task(
                id=task_id,
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                created_at=self._now(),
                assignee_id=assignee_id,
                deadline=deadline,
                description=description or "",
            )
            self.tasks.items[task_id] = task
            self._index_assign(task_id, assignee_id)
            return copy.deepcopy(task)

    def get_task(self, task_id: int) -> Task:
        with self._lock:
            return copy.deepcopy(self._task_or_raise(task_id))

    def list_tasks_by_project(self, project_id: int) -> List[Task]:
        with self._lock:
            self._project_or_raise(project_id)
            tasks = [
                task
                for task in self.tasks.items.values()
                if task.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)
            return [copy.deepcopy(t) for t in tasks]

    def list_tasks_by_assignee(self, assignee_id: int) -> List[Task]:
        with self._lock:
            self._user_or_raise(assignee_id)
            task_ids = sorted(self._tasks_by_assignee.get(assignee_id, set()))
            return [copy.deepcopy(self.tasks.items[tid]) for tid in task_ids]

    def assign_task(self, task_id: int, assignee_id: int) -> Task:
        with self._lock:
            task = self._task_or_raise(task_id)
            self._user_or_raise(assignee_id)
            if task.assignee_id != assignee_id:
                self._index_unassign(task_id, task.assignee_id)
                task.assignee_id = assignee_id
                self._index_assign(task_id, assignee_id)
            return copy.deepcopy(task)

    def reassign_task(self, task_id: int, new_assignee_id: int) -> Task:
        return self.assign_task(task_id, new_assignee_id)

    def unassign_task(self, task_id: int) -> Task:
        with self._lock:
            task = self._task_or_raise(task_id)
            self._index_unassign(task_id, task.assignee_id)
            task.assignee_id = None
            return copy.deepcopy(task)

    def set_deadline(self, task_id: int, deadline: Optional[datetime]) -> Task:
        with self._lock:
            task = self._task_or_raise(task_id)
            if deadline is not None:
                project = self._project_or_raise(task.project_id)
                if deadline < project.start_date:
                    raise ValidationError("deadline cannot precede project start")
            task.deadline = deadline
            return copy.deepcopy(task)

    def update_status(self, task_id: int, status: TaskStatus) -> Task:
        with self._lock:
            task = self._task_or_raise(task_id)
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now

            task.status = status
            return copy.deepcopy(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id: int,
        body: str,
        project_id: Optional[int] = None,
        task_id: Optional[int] = None,
        parent_id: Optional[int] = None,
        attachments: Optional[Sequence[Tuple[str, bytes]]] = None,
    ) -> Message:
        with self._lock:
            self._user_or_raise(author_id)

            if (project_id is None) == (task_id is None):
                raise ValidationError(
                    "exactly one of project_id or task_id must be provided"
                )
            if project_id is not None:
                self._project_or_raise(project_id)
            if task_id is not None:
                self._task_or_raise(task_id)
            if parent_id is not None:
                self._message_or_raise(parent_id)

            attachment_specs = list(attachments) if attachments else []
            body_text = body if isinstance(body, str) else ""
            if not body_text.strip() and not attachment_specs:
                raise ValidationError("message body or an attachment is required")

            now = self._now()
            built_attachments = [
                self._build_attachment(name, data, author_id, now)
                for name, data in attachment_specs
            ]

            message_id = self._next_id()
            message = Message(
                id=message_id,
                author_id=author_id,
                body=body_text,
                created_at=now,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=built_attachments,
            )
            self.messages.items[message_id] = message
            return copy.deepcopy(message)

    @staticmethod
    def _build_attachment(
        filename: str, data: bytes, uploaded_by: int, uploaded_at: datetime
    ) -> Attachment:
        if filename is None or (isinstance(filename, str) and not filename.strip()):
            raise ValidationError("attachment filename is required")
        size = len(data) if data is not None else 0
        return Attachment(
            filename=filename,
            size=size,
            uploaded_by=uploaded_by,
            uploaded_at=uploaded_at,
        )

    def edit_message(self, message_id: int, editor_id: int, new_body: str) -> Message:
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit this message")
            body_text = new_body if isinstance(new_body, str) else ""
            if not body_text.strip() and not message.attachments:
                raise ValidationError("message body or an attachment is required")
            message.body = body_text
            message.edited_at = self._now()
            return copy.deepcopy(message)

    def add_attachment(
        self, message_id: int, uploader_id: int, filename: str, data: bytes
    ) -> Message:
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach to this message")
            attachment = self._build_attachment(
                filename, data, uploader_id, self._now()
            )
            message.attachments.append(attachment)
            return copy.deepcopy(message)

    def list_messages_by_project(self, project_id: int) -> List[Message]:
        with self._lock:
            self._project_or_raise(project_id)
            messages = [
                message
                for message in self.messages.items.values()
                if message.project_id == project_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def list_messages_by_task(self, task_id: int) -> List[Message]:
        with self._lock:
            self._task_or_raise(task_id)
            messages = [
                message
                for message in self.messages.items.values()
                if message.task_id == task_id
            ]
            messages.sort(key=lambda m: m.id)
            return [copy.deepcopy(m) for m in messages]

    def delete_message(self, message_id: int, requester_id: int) -> None:
        with self._lock:
            message = self._message_or_raise(message_id)
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete this message")
            self.messages.items.pop(message_id, None)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def _tasks_for_user(self, user_id: int) -> List[Task]:
        return [
            self.tasks.items[tid]
            for tid in self._tasks_by_assignee.get(user_id, set())
            if tid in self.tasks.items
        ]

    def get_completion_rate(self, user_id: int) -> float:
        with self._lock:
            self._user_or_raise(user_id)
            tasks = self._tasks_for_user(user_id)
            if not tasks:
                return 0.0
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            return completed / len(tasks)

    def get_average_completion_time(self, user_id: int) -> Optional[float]:
        with self._lock:
            self._user_or_raise(user_id)
            durations = [
                (t.completed_at - t.started_at).total_seconds()
                for t in self._tasks_for_user(user_id)
                if t.status == TaskStatus.COMPLETED
                and t.completed_at is not None
                and t.started_at is not None
            ]
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(
        self,
        rater_id: int,
        ratee_id: int,
        score: int,
        feedback: str = "",
        task_id: Optional[int] = None,
    ) -> Rating:
        with self._lock:
            self._user_or_raise(rater_id)
            self._user_or_raise(ratee_id)
            if task_id is not None:
                self._task_or_raise(task_id)
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if not isinstance(score, int) or isinstance(score, bool):
                raise ValidationError("score must be an integer between 1 and 5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")

            rating_id = self._next_id()
            rating = Rating(
                id=rating_id,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                created_at=self._now(),
                feedback=feedback or "",
                task_id=task_id,
            )
            self.performance.items[rating_id] = rating
            self._ratings_by_ratee.setdefault(ratee_id, []).append(rating_id)
            return copy.deepcopy(rating)

    def _ratings_for_user(self, user_id: int) -> List[Rating]:
        rating_ids = sorted(self._ratings_by_ratee.get(user_id, []))
        return [self.performance.items[rid] for rid in rating_ids]

    def get_ratings_summary(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._user_or_raise(user_id)
            ratings = self._ratings_for_user(user_id)
            count = len(ratings)
            average = (
                sum(r.score for r in ratings) / count if count else 0.0
            )
            return {
                "count": count,
                "average": average,
                "ratings": [copy.deepcopy(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._user_or_raise(user_id)
            tasks = self._tasks_for_user(user_id)
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            average_time = self.get_average_completion_time(user_id)
            summary = self.get_ratings_summary(user_id)
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": average_time,
                "rating_count": summary["count"],
                "rating_average": summary["average"],
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def _user_task_stats(self, tasks: Sequence[Task]) -> Dict[str, object]:
        total = len(tasks)
        completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
        in_progress = sum(1 for t in tasks if t.status == TaskStatus.IN_PROGRESS)
        not_started = sum(1 for t in tasks if t.status == TaskStatus.NOT_STARTED)
        durations = [
            (t.completed_at - t.started_at).total_seconds()
            for t in tasks
            if t.status == TaskStatus.COMPLETED
            and t.completed_at is not None
            and t.started_at is not None
        ]
        average_time = sum(durations) / len(durations) if durations else None
        return {
            "total_tasks": total,
            "completed_tasks": completed,
            "in_progress_tasks": in_progress,
            "not_started_tasks": not_started,
            "completion_rate": completed / total if total else 0.0,
            "average_completion_time": average_time,
        }

    def project_progress_report(self, project_id: int) -> Dict[str, object]:
        with self._lock:
            self._project_or_raise(project_id)
            now = self._now()
            tasks = [
                task
                for task in self.tasks.items.values()
                if task.project_id == project_id
            ]
            tasks.sort(key=lambda t: t.id)

            status_counts = {status.value: 0 for status in TaskStatus}
            overdue = 0
            per_assignee: Dict[int, Dict[str, object]] = {}
            grouped: Dict[int, List[Task]] = {}
            for task in tasks:
                status_counts[task.status.value] += 1
                if (
                    task.deadline is not None
                    and task.deadline < now
                    and task.status != TaskStatus.COMPLETED
                ):
                    overdue += 1
                if task.assignee_id is not None:
                    grouped.setdefault(task.assignee_id, []).append(task)

            for assignee_id, assignee_tasks in grouped.items():
                per_assignee[assignee_id] = self._user_task_stats(assignee_tasks)

            total = len(tasks)
            completed = status_counts[TaskStatus.COMPLETED.value]
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completed / total if total else 0.0,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(
        self, project_id: Optional[int] = None
    ) -> Dict[str, object]:
        with self._lock:
            if project_id is not None:
                self._project_or_raise(project_id)

            grouped: Dict[int, List[Task]] = {}
            for task in self.tasks.items.values():
                if project_id is not None and task.project_id != project_id:
                    continue
                if task.assignee_id is None:
                    continue
                grouped.setdefault(task.assignee_id, []).append(task)

            rows = []
            for user_id in sorted(grouped):
                user = self.users.items.get(user_id)
                stats = self._user_task_stats(grouped[user_id])
                ratings = self._ratings_for_user(user_id)
                rating_count = len(ratings)
                rating_average = (
                    sum(r.score for r in ratings) / rating_count
                    if rating_count
                    else 0.0
                )
                row = {
                    "user_id": user_id,
                    "username": user.username if user is not None else None,
                    "rating_count": rating_count,
                    "rating_average": rating_average,
                }
                row.update(stats)
                rows.append(row)

            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id: int) -> Dict[str, object]:
        with self._lock:
            self._user_or_raise(user_id)
            tasks = sorted(self._tasks_for_user(user_id), key=lambda t: t.id)
            stats = self._user_task_stats(tasks)
            ratings = self._ratings_for_user(user_id)
            rating_count = len(ratings)
            rating_average = (
                sum(r.score for r in ratings) / rating_count
                if rating_count
                else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "project_id": t.project_id,
                }
                for t in tasks
            ]
            report = {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }
            report.update(stats)
            return report

    # ------------------------------------------------------------------
    # Report export
    # ------------------------------------------------------------------
    def export_report(self, report: Dict[str, object], fmt: ReportFormat):
        if not isinstance(fmt, ReportFormat):
            raise ValidationError("fmt must be a ReportFormat")
        if not isinstance(report, dict):
            raise ValidationError("report must be a mapping produced by a report method")
        if fmt == ReportFormat.CSV:
            return self._export_csv(report)
        return self._export_pdf(report)

    @staticmethod
    def _csv_cell(value: object) -> str:
        if value is None:
            return ""
        if isinstance(value, float):
            return repr(value)
        if isinstance(value, (dict, list, tuple)):
            return str(value)
        return str(value)

    def _export_csv(self, report: Dict[str, object]) -> str:
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        rows = report.get("rows")
        if isinstance(rows, list) and rows and all(isinstance(r, dict) for r in rows):
            headers: List[str] = []
            for record in rows:
                for key in record.keys():
                    if key not in headers:
                        headers.append(key)
            writer.writerow(headers)
            for record in rows:
                writer.writerow([self._csv_cell(record.get(h)) for h in headers])
        else:
            headers = list(report.keys())
            writer.writerow(headers)
            writer.writerow([self._csv_cell(report[h]) for h in headers])
        return buffer.getvalue()

    def _report_to_lines(self, report: Dict[str, object]) -> List[str]:
        lines: List[str] = []
        rows = report.get("rows")
        for key, value in report.items():
            if key == "rows" and isinstance(value, list):
                continue
            lines.append("{0}: {1}".format(key, self._csv_cell(value)))
        if isinstance(rows, list):
            lines.append("rows:")
            for record in rows:
                if isinstance(record, dict):
                    parts = ", ".join(
                        "{0}={1}".format(k, self._csv_cell(v))
                        for k, v in record.items()
                    )
                else:
                    parts = self._csv_cell(record)
                lines.append("  - " + parts)
        return lines or [""]

    @staticmethod
    def _pdf_escape(text: str) -> str:
        return (
            text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
        )

    def _export_pdf(self, report: Dict[str, object]) -> bytes:
        lines = self._report_to_lines(report)

        content_ops = ["BT", "/F1 12 Tf", "16 TL", "50 750 Td"]
        first = True
        for line in lines:
            safe = self._pdf_escape(line[:110])
            if first:
                content_ops.append("({0}) Tj".format(safe))
                first = False
            else:
                content_ops.append("T*")
                content_ops.append("({0}) Tj".format(safe))
        content_ops.append("ET")
        content = "\n".join(content_ops).encode("latin-1", "replace")

        objects: List[bytes] = [
            b"<< /Type /Catalog /Pages 2 0 R >>",
            b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
            (
                b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
                b"/Resources << /Font << /F1 5 0 R >> >> /Contents 4 0 R >>"
            ),
            (
                b"<< /Length "
                + str(len(content)).encode("ascii")
                + b" >>\nstream\n"
                + content
                + b"\nendstream"
            ),
            b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>",
        ]

        pdf = bytearray(b"%PDF-1.4\n")
        offsets: List[int] = []
        for index, body in enumerate(objects, start=1):
            offsets.append(len(pdf))
            pdf += str(index).encode("ascii") + b" 0 obj\n" + body + b"\nendobj\n"

        xref_position = len(pdf)
        size = len(objects) + 1
        pdf += b"xref\n"
        pdf += b"0 " + str(size).encode("ascii") + b"\n"
        pdf += b"0000000000 65535 f \n"
        for offset in offsets:
            pdf += "{0:010d} 00000 n \n".format(offset).encode("ascii")
        pdf += b"trailer\n"
        pdf += b"<< /Size " + str(size).encode("ascii") + b" /Root 1 0 R >>\n"
        pdf += b"startxref\n"
        pdf += str(xref_position).encode("ascii") + b"\n"
        pdf += b"%%EOF\n"
        return bytes(pdf)


